INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10011, 4, "【加速】4以上：\n重複可能の行動速度アップ（【加速】数×5％）\n", 1);
