INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10013, 15, "【加速】15以上：\n【烈風】20：【烈風】をすべて消費して\nＴＰ1000回復\nダメージブースト＋10％\n", 1);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10021, 4, "【弱体】4以上：\n敵への継続ダメージアップ（【弱体】数×50％）\n", 2);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10022, 9, "【弱体】9以上：\n敵にデバフを付与するたびに敵に【衰弱】＋１\n（最大66）\n敵の物理/魔法被ダメアップ（【衰弱】数×2％）\n", 2);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10023, 15, "【弱体】15以上：\n敵の【衰弱】66：１秒ごとに最大ＨＰの5％の割合\nダメージ（最大100万）\n", 2);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10031, 4, "【会心】4以上：\n物理/魔法クリダメアップ（【会心】数×5％）\n物理/魔法クリティカルアップ（【会心】数×200）\n", 3);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10032, 9, "【会心】9以上：\nクリティカルするたびに敵に【看破】＋１（最大99）\n敵の物理/魔法被クリダメアップ（【看破】数×1％）\n", 3);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10033, 15, "【会心】15以上：\n敵の【看破】99：攻撃時追加ダメージ＋30％\n", 3);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10041, 4, "【強化】4以上：\nダメージブーストアップ（【強化】数×2％）\n", 4);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10042, 9, "【強化】9以上：\n味方からバフを受けるたびに【高揚】＋１（最大99）\n物理/魔法攻撃力アップ（【高揚】数×1％）\n", 4);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10043, 15, "【強化】15以上：\n【高揚】99：１秒ごとに物理/魔法攻撃力ダウンと\n物理/魔法防御力ダウン効果解除\n物理/魔法攻撃力アップ（現在値＋10％）\n", 4);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10051, 4, "【守備】4以上：\n全ダメージカット（【守備】数×2％）\n", 5);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10052, 9, "【守備】9以上：\n敵から攻撃かデバフを受けるたびに【闘志】＋１\n（最大15）\n与ダメアップ（【闘志】数×5％）\nＨＰ吸収アップ（【闘志】数×5）\n", 5);
INSERT INTO `v1_f5ce8209638b698574526242bd9631c7fdf4e85dcef6cbfa07ab37f2a0aca603` VALUES (10053, 15, "【守備】15以上：\n【闘志】15：【闘志】をすべて消費して\n与ダメ＋50％\nダメージブースト＋25％\n", 5);
